SELECT ?date WHERE {
  ?season wdt:P31 wd:Q1985178 ;
          wdt:P361 wd:Q11151 ;
          wdt:P580 ?seasonStart .
  FILTER(YEAR(?seasonStart) = 2023)
  ?round wdt:P361 ?season ;
         wdt:P1545 "5" ;
         wdt:P585 ?date .
} ORDER BY ?date LIMIT 10

